    #[test]
    fn test_is_synced() {
        let mut tracker = HeartbeatTracker::new();
        tracker.last_synced_block = 100;
        tracker.hydrated = true;

        // Exactly one ahead of last_synced — still synced
        assert!(tracker.is_synced(101));
        // Tracker is ahead of the requested block — also synced
        assert!(tracker.is_synced(100));
        // Too far ahead of tracker — not synced
        assert!(!tracker.is_synced(200));
    }

